  1→/**
  2→ * Graph-Reactive Coordination Acceptance Test Kit
  3→ *
  4→ * Extends the shared acceptance-test-kit with reactive coordination helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   GET  /api/workspaces/:workspaceId/feed/stream   (SSE feed stream)
  9→ *   GET  /api/workspaces/:workspaceId/feed           (initial feed state)
 10→ *   POST /proxy/llm/anthropic/v1/messages            (LLM proxy -- context injection)
 11→ *   POST /api/mcp/:workspaceId/context               (MCP context resolution)
 12→ *   SurrealDB direct queries                         (verification of outcomes + seed data)
 13→ */
 14→import { RecordId, type Surreal } from "surrealdb";
 15→import { embedMany } from "ai";
 16→
 17→// ---------------------------------------------------------------------------
 18→// Re-exports from shared kit
 19→// ---------------------------------------------------------------------------
 20→
 21→export {
 22→  setupAcceptanceSuite,
 23→  createTestUser,
 24→  createTestUserWithMcp,
 25→  fetchJson,
 26→  fetchRaw,
 27→  collectSseEvents,
 28→  testAI,
 29→  type AcceptanceTestRuntime,
 30→  type TestUser,
 31→  type TestUserWithMcp,
 32→} from "../acceptance-test-kit";
 33→
 34→import {
 35→  setupAcceptanceSuite,
 36→  fetchRaw,
 37→  testAI,
 38→  type AcceptanceTestRuntime,
 39→  type TestUser,
 40→} from "../acceptance-test-kit";
 41→
 42→// ---------------------------------------------------------------------------
 43→// Domain Types
 44→// ---------------------------------------------------------------------------
 45→
 46→export type ObservationSeverity = "info" | "warning" | "conflict";
 47→export type ObservationStatus = "open" | "acknowledged" | "resolved";
 48→
 49→export type FeedItem = {
 50→  id: string;
 51→  type: string;
 52→  tier: string;
 53→  title: string;
 54→  severity?: string;
 55→  source?: string;
 56→  created_at: string;
 57→};
 58→
 59→export type FeedStreamEvent = {
 60→  items: FeedItem[];
 61→  removals?: string[];
 62→};
 63→
 64→export type AgentDescription = {
 65→  agentId: string;
 66→  agentType: string;
 67→  description: string;
 68→  descriptionEmbedding?: number[];
 69→};
 70→
 71→// ---------------------------------------------------------------------------
 72→// Suite Setup
 73→// ---------------------------------------------------------------------------
 74→
 75→/**
 76→ * Sets up a reactive coordination acceptance test suite with an isolated server + DB.
 77→ */
 78→export function setupReactiveSuite(
 79→  suiteName: string,
 80→): () => AcceptanceTestRuntime {
 81→  return setupAcceptanceSuite(suiteName);
 82→}
 83→
 84→// ---------------------------------------------------------------------------
 85→// Workspace and Identity Helpers
 86→// ---------------------------------------------------------------------------
 87→
 88→/**
 89→ * Creates a workspace directly in SurrealDB for reactive coordination tests.
 90→ */
 91→export async function createTestWorkspace(
 92→  surreal: Surreal,
 93→  suffix: string,
 94→): Promise<{ workspaceId: string; identityId: string }> {
 95→  const workspaceId = `ws-${crypto.randomUUID()}`;
 96→  const identityId = `id-${crypto.randomUUID()}`;
 97→  const workspaceRecord = new RecordId("workspace", workspaceId);
 98→  const identityRecord = new RecordId("identity", identityId);
 99→
100→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
101→    workspace: workspaceRecord,
102→    content: {
103→      name: `Reactive Test Workspace ${suffix}`,
104→      status: "active",
105→      onboarding_complete: true,
106→      onboarding_turn_count: 0,
107→      onboarding_summary_pending: false,
108→      onboarding_started_at: new Date(),
109→      created_at: new Date(),
110→    },
111→  });
112→
113→  await surreal.query(`CREATE $identity CONTENT $content;`, {
114→    identity: identityRecord,
115→    content: {
116→      name: `Test Admin ${suffix}`,
117→      type: "human",
118→      identity_status: "active",
119→      workspace: workspaceRecord,
120→      created_at: new Date(),
121→    },
122→  });
123→
124→  await surreal.query(
125→    `RELATE $identity->member_of->$workspace SET added_at = time::now();`,
126→    { identity: identityRecord, workspace: workspaceRecord },
127→  );
128→
129→  return { workspaceId, identityId };
130→}
131→
132→// ---------------------------------------------------------------------------
133→// Observation Helpers (Graph Write -- Triggers LIVE SELECT)
134→// ---------------------------------------------------------------------------
135→
136→/**
137→ * Creates an observation in the graph, simulating what the Observer agent produces.
138→ * This is the primary event source that triggers the reactive coordination layer.
139→ */
140→export async function createObservation(
141→  surreal: Surreal,
142→  workspaceId: string,
143→  options: {
144→    text: string;
145→    severity: ObservationSeverity;
146→    sourceAgent: string;
147→    category?: string;
148→    embedding?: number[];
149→    targetEntity?: { table: string; id: string };
150→  },
151→): Promise<{ observationId: string }> {
152→  const observationId = `obs-${crypto.randomUUID()}`;
153→  const observationRecord = new RecordId("observation", observationId);
154→  const workspaceRecord = new RecordId("workspace", workspaceId);
155→
156→  const content: Record<string, unknown> = {
157→    text: options.text,
158→    severity: options.severity,
159→    status: "open",
160→    source_agent: options.sourceAgent,
161→    workspace: workspaceRecord,
162→    created_at: new Date(),
163→  };
164→
165→  if (options.category) {
166→    content.category = options.category;
167→  }
168→  if (options.embedding) {
169→    content.embedding = options.embedding;
170→  }
171→
172→  await surreal.query(`CREATE $obs CONTENT $content;`, {
173→    obs: observationRecord,
174→    content,
175→  });
176→
177→  // If targeting a specific entity, create the observes edge
178→  if (options.targetEntity) {
179→    const targetRecord = new RecordId(options.targetEntity.table, options.targetEntity.id);
180→    await surreal.query(
181→      `RELATE $obs->observes->$target SET added_at = time::now();`,
182→      { obs: observationRecord, target: targetRecord },
183→    );
184→  }
185→
186→  return { observationId };
187→}
188→
189→/**
190→ * Creates an observation AND triggers the coordinator webhook endpoint.
191→ * In production, the SurrealDB DEFINE EVENT fires the webhook automatically.
192→ * In tests, we simulate this by POSTing to the coordinator endpoint directly.
193→ */
194→export async function createObservationWithCoordinator(
195→  surreal: Surreal,
196→  baseUrl: string,
197→  workspaceId: string,
198→  options: {
199→    text: string;
200→    severity: ObservationSeverity;
201→    sourceAgent: string;
202→    category?: string;
203→    embedding?: number[];
204→    targetEntity?: { table: string; id: string };
205→  },
206→): Promise<{ observationId: string }> {
207→  const result = await createObservation(surreal, workspaceId, options);
208→
209→  // Simulate DEFINE EVENT webhook — POST to agent activator endpoint
210→  await fetch(`${baseUrl}/api/internal/activator/observation`, {
211→    method: "POST",
212→    headers: { "Content-Type": "application/json" },
213→    body: JSON.stringify({
214→      observation_id: result.observationId,
215→      workspace: workspaceId,
216→      text: options.text,
217→      severity: options.severity,
218→      source_agent: options.sourceAgent,
219→    }),
220→  });
221→
222→  return result;
223→}
224→
225→/**
226→ * Creates multiple observations in rapid succession with coordinator webhook calls.
227→ */
228→export async function createObservationBurstWithCoordinator(
229→  surreal: Surreal,
230→  baseUrl: string,
231→  workspaceId: string,
232→  options: {
233→    count: number;
234→    sourceAgent: string;
235→    targetEntity: { table: string; id: string };
236→    severity: ObservationSeverity;
237→    textPrefix: string;
238→    embedding?: number[];
239→  },
240→): Promise<string[]> {
241→  // Use provided embedding or generate a fake one so the coordinator webhook accepts the payload
242→  const embedding = options.embedding ?? fakeEmbedding(42);
243→  const ids: string[] = [];
244→  for (let i = 0; i < options.count; i++) {
245→    const { observationId } = await createObservationWithCoordinator(surreal, baseUrl, workspaceId, {
246→      text: `${options.textPrefix} (${i + 1} of ${options.count})`,
247→      severity: options.severity,
248→      sourceAgent: options.sourceAgent,
249→      targetEntity: options.targetEntity,
250→      embedding,
251→    });
252→    ids.push(observationId);
253→  }
254→  return ids;
255→}
256→
257→/**
258→ * Creates multiple observations in rapid succession for loop dampening tests.
259→ */
260→export async function createObservationBurst(
261→  surreal: Surreal,
262→  workspaceId: string,
263→  options: {
264→    count: number;
265→    sourceAgent: string;
266→    targetEntity: { table: string; id: string };
267→    severity: ObservationSeverity;
268→    textPrefix: string;
269→  },
270→): Promise<string[]> {
271→  const ids: string[] = [];
272→  for (let i = 0; i < options.count; i++) {
273→    const { observationId } = await createObservation(surreal, workspaceId, {
274→      text: `${options.textPrefix} (${i + 1} of ${options.count})`,
275→      severity: options.severity,
276→      sourceAgent: options.sourceAgent,
277→      targetEntity: options.targetEntity,
278→    });
279→    ids.push(observationId);
280→  }
281→  return ids;
282→}
