516→// ---------------------------------------------------------------------------
517→// Feed Stream Helpers
518→// ---------------------------------------------------------------------------
519→
520→/**
521→ * Opens an SSE connection to the governance feed stream for a workspace.
522→ * Returns a controller that can collect events and close the connection.
523→ */
524→export function openFeedStream(
525→  baseUrl: string,
526→  workspaceId: string,
527→  user: TestUser,
528→  options?: { lastEventId?: string },
529→): FeedStreamController {
530→  return new FeedStreamController(baseUrl, workspaceId, user, options);
531→}
532→
533→export class FeedStreamController {
534→  private events: FeedStreamEvent[] = [];
535→  private rawEvents: string[] = [];
536→  private reader: ReadableStreamDefaultReader<Uint8Array> | undefined;
537→  private abortController = new AbortController();
538→  private buffer = "";
539→  private decoder = new TextDecoder();
540→  private connected = false;
541→  private connectionPromise: Promise<void> | undefined;
542→  private lastEventId: string | undefined;
543→
544→  constructor(
545→    private baseUrl: string,
546→    private workspaceId: string,
547→    private user: TestUser,
548→    private options?: { lastEventId?: string },
549→  ) {
550→    this.lastEventId = options?.lastEventId;
551→  }
552→
553→  /** Start listening for SSE events. */
554→  async connect(): Promise<void> {
555→    this.connectionPromise = this._connect();
556→    // Give the connection a moment to establish
557→    await new Promise((resolve) => setTimeout(resolve, 200));
558→  }
559→
560→  /** Get the last event ID received from the server. */
561→  getLastEventId(): string | undefined {
562→    return this.lastEventId;
563→  }
564→
565→  private async _connect(): Promise<void> {
566→    const url = `${this.baseUrl}/api/workspaces/${this.workspaceId}/feed/stream`;
567→    const headers: Record<string, string> = {
568→      Accept: "text/event-stream",
569→      ...this.user.headers,
570→    };
571→    if (this.lastEventId) {
572→      headers["Last-Event-ID"] = this.lastEventId;
573→    }
574→    const response = await fetch(url, {
575→      headers,
576→      signal: this.abortController.signal,
577→    });
578→
579→    if (!response.ok || !response.body) {
580→      throw new Error(`Failed to open feed stream (${response.status})`);
581→    }
582→
583→    this.connected = true;
584→    this.reader = response.body.getReader();
585→
586→    try {
587→      while (true) {
588→        const { value, done } = await this.reader.read();
589→        if (done) break;
590→
591→        this.buffer += this.decoder.decode(value, { stream: true });
592→        const segments = this.buffer.split("\n\n");
593→        this.buffer = segments.pop() ?? "";
594→
595→        for (const segment of segments) {
596→          const lines = segment.split("\n");
597→          const idLine = lines.find((line) => line.startsWith("id: "));
598→          const dataLine = lines.find((line) => line.startsWith("data: "));
599→          if (!dataLine) continue;
600→
601→          // Track the last event ID for reconnection
602→          if (idLine) {
603→            this.lastEventId = idLine.slice("id: ".length).trim();
604→          }
605→
606→          const raw = dataLine.slice("data: ".length);
607→          this.rawEvents.push(raw);
608→
609→          try {
610→            const event = JSON.parse(raw) as FeedStreamEvent;
611→            this.events.push(event);
612→          } catch {
613→            // Non-JSON event (keep-alive comment, etc.)
614→          }
615→        }
616→      }
617→    } catch (e: unknown) {
618→      // AbortError is expected when we close the stream
619→      if (e instanceof DOMException && e.name === "AbortError") return;
620→      if (e instanceof Error && e.message.includes("abort")) return;
621→      throw e;
622→    }
623→  }
624→
625→  /** Wait for at least N feed_update events, with timeout. */
626→  async waitForEvents(count: number, timeoutMs: number = 5000): Promise<FeedStreamEvent[]> {
627→    const start = Date.now();
628→    while (this.events.length < count && Date.now() - start < timeoutMs) {
629→      await new Promise((resolve) => setTimeout(resolve, 100));
630→    }
631→    return [...this.events];
632→  }
633→
634→  /** Get all collected events so far. */
635→  getEvents(): FeedStreamEvent[] {
636→    return [...this.events];
637→  }
638→
639→  /** Get all raw event strings. */
640→  getRawEvents(): string[] {
641→    return [...this.rawEvents];
642→  }
643→
644→  /** Whether the stream connection was established. */
645→  isConnected(): boolean {
646→    return this.connected;
647→  }
648→
649→  /** Close the SSE connection. */
650→  close(): void {
651→    this.abortController.abort();
652→    this.connected = false;
653→  }
654→}
