788→
789→/**
790→ * Queries agent sessions created by the activator (orchestrator_status = "spawning").
791→ * These are sessions started by the agent activator when LLM classification
792→ * matched an agent type to an observation.
793→ */
794→export async function getActivatedSessions(
795→  surreal: Surreal,
796→  workspaceId: string,
797→): Promise<Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>> {
798→  const workspaceRecord = new RecordId("workspace", workspaceId);
