/**
 * Graph-Reactive Coordination Acceptance Test Kit
 *
 * Extends the shared acceptance-test-kit with reactive coordination helpers.
 * All helpers use business language -- no technical jargon in function names.
 *
 * Driving ports:
 *   GET  /api/workspaces/:workspaceId/feed/stream   (SSE feed stream)
 *   GET  /api/workspaces/:workspaceId/feed           (initial feed state)
 *   POST /proxy/llm/anthropic/v1/messages            (LLM proxy -- context injection)
 *   POST /api/mcp/:workspaceId/context               (MCP context resolution)
 *   SurrealDB direct queries                         (verification of outcomes + seed data)
 */
import { RecordId, type Surreal } from "surrealdb";
import { embedMany } from "ai";

// ---------------------------------------------------------------------------
// Re-exports from shared kit
// ---------------------------------------------------------------------------

export {
  setupAcceptanceSuite,
  createTestUser,
  createTestUserWithMcp,
  fetchJson,
  fetchRaw,
  collectSseEvents,
  testAI,
  type AcceptanceTestRuntime,
  type TestUser,
  type TestUserWithMcp,
} from "../acceptance-test-kit";

import {
  setupAcceptanceSuite,
  fetchRaw,
  testAI,
  type AcceptanceTestRuntime,
  type TestUser,
} from "../acceptance-test-kit";

// ---------------------------------------------------------------------------
// Domain Types
// ---------------------------------------------------------------------------

export type ObservationSeverity = "info" | "warning" | "conflict";
export type ObservationStatus = "open" | "acknowledged" | "resolved";

export type FeedItem = {
  id: string;
  type: string;
  tier: string;
  title: string;
  severity?: string;
  source?: string;
  created_at: string;
};

export type FeedStreamEvent = {
  items: FeedItem[];
  removals?: string[];
};

export type AgentDescription = {
  agentId: string;
  agentType: string;
  description: string;
  descriptionEmbedding?: number[];
};

// ---------------------------------------------------------------------------
// Suite Setup
// ---------------------------------------------------------------------------

/**
 * Sets up a reactive coordination acceptance test suite with an isolated server + DB.
 */
export function setupReactiveSuite(
  suiteName: string,
): () => AcceptanceTestRuntime {
  return setupAcceptanceSuite(suiteName);
}

// ---------------------------------------------------------------------------
// Workspace and Identity Helpers
// ---------------------------------------------------------------------------

/**
 * Creates a workspace directly in SurrealDB for reactive coordination tests.
 */
export async function createTestWorkspace(
  surreal: Surreal,
  suffix: string,
): Promise<{ workspaceId: string; identityId: string }> {
  const workspaceId = `ws-${crypto.randomUUID()}`;
  const identityId = `id-${crypto.randomUUID()}`;
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const identityRecord = new RecordId("identity", identityId);

  await surreal.query(`CREATE $workspace CONTENT $content;`, {
    workspace: workspaceRecord,
    content: {
      name: `Reactive Test Workspace ${suffix}`,
      status: "active",
      onboarding_complete: true,
      onboarding_turn_count: 0,
      onboarding_summary_pending: false,
      onboarding_started_at: new Date(),
      created_at: new Date(),
    },
  });

  await surreal.query(`CREATE $identity CONTENT $content;`, {
    identity: identityRecord,
    content: {
      name: `Test Admin ${suffix}`,
      type: "human",
      identity_status: "active",
      workspace: workspaceRecord,
      created_at: new Date(),
    },
  });

  await surreal.query(
    `RELATE $identity->member_of->$workspace SET added_at = time::now();`,
    { identity: identityRecord, workspace: workspaceRecord },
  );

  return { workspaceId, identityId };
}

// ---------------------------------------------------------------------------
// Observation Helpers (Graph Write -- Triggers LIVE SELECT)
// ---------------------------------------------------------------------------

/**
 * Creates an observation in the graph, simulating what the Observer agent produces.
 * This is the primary event source that triggers the reactive coordination layer.
 */
export async function createObservation(
  surreal: Surreal,
  workspaceId: string,
  options: {
    text: string;
    severity: ObservationSeverity;
    sourceAgent: string;
    category?: string;
    embedding?: number[];
    targetEntity?: { table: string; id: string };
  },
): Promise<{ observationId: string }> {
  const observationId = `obs-${crypto.randomUUID()}`;
  const observationRecord = new RecordId("observation", observationId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  const content: Record<string, unknown> = {
    text: options.text,
    severity: options.severity,
    status: "open",
    source_agent: options.sourceAgent,
    workspace: workspaceRecord,
    created_at: new Date(),
  };

  if (options.category) {
    content.category = options.category;
  }
  if (options.embedding) {
    content.embedding = options.embedding;
  }

  await surreal.query(`CREATE $obs CONTENT $content;`, {
    obs: observationRecord,
    content,
  });

  // If targeting a specific entity, create the observes edge
  if (options.targetEntity) {
    const targetRecord = new RecordId(options.targetEntity.table, options.targetEntity.id);
    await surreal.query(
      `RELATE $obs->observes->$target SET added_at = time::now();`,
      { obs: observationRecord, target: targetRecord },
    );
  }

  return { observationId };
}

/**
 * Creates an observation AND triggers the coordinator webhook endpoint.
 * In production, the SurrealDB DEFINE EVENT fires the webhook automatically.
 * In tests, we simulate this by POSTing to the coordinator endpoint directly.
 */
export async function createObservationWithCoordinator(
  surreal: Surreal,
  baseUrl: string,
  workspaceId: string,
  options: {
    text: string;
    severity: ObservationSeverity;
    sourceAgent: string;
    category?: string;
    embedding?: number[];
    targetEntity?: { table: string; id: string };
  },
): Promise<{ observationId: string }> {
  const result = await createObservation(surreal, workspaceId, options);

  // Simulate DEFINE EVENT webhook — POST to agent activator endpoint
  await fetch(`${baseUrl}/api/internal/activator/observation`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      observation_id: result.observationId,
      workspace: workspaceId,
      text: options.text,
      severity: options.severity,
      source_agent: options.sourceAgent,
    }),
  });

  return result;
}

/**
 * Creates multiple observations in rapid succession with coordinator webhook calls.
 */
export async function createObservationBurstWithCoordinator(
  surreal: Surreal,
  baseUrl: string,
  workspaceId: string,
  options: {
    count: number;
    sourceAgent: string;
    targetEntity: { table: string; id: string };
    severity: ObservationSeverity;
    textPrefix: string;
    embedding?: number[];
  },
): Promise<string[]> {
  // Use provided embedding or generate a fake one so the coordinator webhook accepts the payload
  const embedding = options.embedding ?? fakeEmbedding(42);
  const ids: string[] = [];
  for (let i = 0; i < options.count; i++) {
    const { observationId } = await createObservationWithCoordinator(surreal, baseUrl, workspaceId, {
      text: `${options.textPrefix} (${i + 1} of ${options.count})`,
      severity: options.severity,
      sourceAgent: options.sourceAgent,
      targetEntity: options.targetEntity,
      embedding,
    });
    ids.push(observationId);
  }
  return ids;
}

/**
 * Creates multiple observations in rapid succession for loop dampening tests.
 */
export async function createObservationBurst(
  surreal: Surreal,
  workspaceId: string,
  options: {
    count: number;
    sourceAgent: string;
    targetEntity: { table: string; id: string };
    severity: ObservationSeverity;
    textPrefix: string;
  },
): Promise<string[]> {
  const ids: string[] = [];
  for (let i = 0; i < options.count; i++) {
    const { observationId } = await createObservation(surreal, workspaceId, {
      text: `${options.textPrefix} (${i + 1} of ${options.count})`,
      severity: options.severity,
      sourceAgent: options.sourceAgent,
      targetEntity: options.targetEntity,
    });
    ids.push(observationId);
  }
  return ids;
}

// ---------------------------------------------------------------------------
// Decision Helpers
// ---------------------------------------------------------------------------

/**
 * Creates a decision in the graph.
 */
export async function createDecision(
  surreal: Surreal,
  workspaceId: string,
  options: {
    summary: string;
    status?: string;
    embedding?: number[];
  },
): Promise<{ decisionId: string }> {
  const decisionId = `dec-${crypto.randomUUID()}`;
  const decisionRecord = new RecordId("decision", decisionId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $dec CONTENT $content;`, {
    dec: decisionRecord,
    content: {
      summary: options.summary,
      status: options.status ?? "provisional",
      workspace: workspaceRecord,
      created_at: new Date(),
      updated_at: new Date(),
      ...(options.embedding ? { embedding: options.embedding } : {}),
    },
  });

  return { decisionId };
}

/**
 * Confirms a provisional decision, simulating the chat agent confirming it.
 */
export async function confirmDecision(
  surreal: Surreal,
  decisionId: string,
): Promise<void> {
  const decisionRecord = new RecordId("decision", decisionId);
  await surreal.query(
    `UPDATE $dec SET status = "confirmed", updated_at = time::now();`,
    { dec: decisionRecord },
  );
}

/**
 * Supersedes a decision with a new one.
 */
export async function supersedeDecision(
  surreal: Surreal,
  oldDecisionId: string,
  newDecisionId: string,
): Promise<void> {
  const oldRecord = new RecordId("decision", oldDecisionId);
  const newRecord = new RecordId("decision", newDecisionId);
  await surreal.query(
    `UPDATE $old SET status = "superseded", updated_at = time::now();`,
    { old: oldRecord },
  );
  await surreal.query(
    `RELATE $new->supersedes->$old SET created_at = time::now();`,
    { new: newRecord, old: oldRecord },
  );
}

// ---------------------------------------------------------------------------
// Task Helpers
// ---------------------------------------------------------------------------

/**
 * Creates a task in the graph.
 */
export async function createTask(
  surreal: Surreal,
  workspaceId: string,
  options: {
    title: string;
    status?: string;
    embedding?: number[];
  },
): Promise<{ taskId: string }> {
  const taskId = `task-${crypto.randomUUID()}`;
  const taskRecord = new RecordId("task", taskId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  await surreal.query(`CREATE $task CONTENT $content;`, {
    task: taskRecord,
    content: {
      title: options.title,
      status: options.status ?? "open",
      workspace: workspaceRecord,
      created_at: new Date(),
      updated_at: new Date(),
      ...(options.embedding ? { embedding: options.embedding } : {}),
    },
  });

  return { taskId };
}

/**
 * Blocks a task, simulating a human or agent marking it blocked.
 */
export async function blockTask(
  surreal: Surreal,
  taskId: string,
): Promise<void> {
  const taskRecord = new RecordId("task", taskId);
  await surreal.query(
    `UPDATE $task SET status = "blocked", updated_at = time::now();`,
    { task: taskRecord },
  );
}

/**
 * Creates a dependency between a task and a decision.
 */
export async function linkTaskToDecision(
  surreal: Surreal,
  taskId: string,
  decisionId: string,
): Promise<void> {
  const taskRecord = new RecordId("task", taskId);
  const decisionRecord = new RecordId("decision", decisionId);
  await surreal.query(
    `RELATE $task->depends_on->$dec SET created_at = time::now();`,
    { task: taskRecord, dec: decisionRecord },
  );
}

// ---------------------------------------------------------------------------
// Agent Session Helpers
// ---------------------------------------------------------------------------

/**
 * Creates an agent with a description, simulating agent registration.
 * The description (text) is used by the agent activator's LLM classification (ADR-061).
 */
export async function registerAgent(
  surreal: Surreal,
  workspaceId: string,
  identityId: string,
  options: {
    agentType: string;
    description?: string;
    descriptionEmbedding?: number[];
  },
): Promise<{ agentId: string }> {
  const agentId = `agent-${crypto.randomUUID()}`;
  const agentRecord = new RecordId("agent", agentId);
  const identityRecord = new RecordId("identity", identityId);

  const content: Record<string, unknown> = {
    agent_type: options.agentType,
    managed_by: identityRecord,
    created_at: new Date(),
  };

  if (options.description) {
    content.description = options.description;
  }
  if (options.descriptionEmbedding) {
    content.description_embedding = options.descriptionEmbedding;
  }

  await surreal.query(`CREATE $agent CONTENT $content;`, {
    agent: agentRecord,
    content,
  });

  return { agentId };
}

/**
 * Creates an active agent session, simulating an agent starting work.
 */
export async function startAgentSession(
  surreal: Surreal,
  workspaceId: string,
  options: {
    agentType: string;
    taskId?: string;
    description?: string;
    descriptionEmbedding?: number[];
  },
): Promise<{ sessionId: string }> {
  const sessionId = `sess-${crypto.randomUUID()}`;
  const sessionRecord = new RecordId("agent_session", sessionId);
  const workspaceRecord = new RecordId("workspace", workspaceId);

  const content: Record<string, unknown> = {
    agent: options.agentType,
    started_at: new Date(),
    workspace: workspaceRecord,
    orchestrator_status: "active",
    created_at: new Date(),
  };

  if (options.taskId) {
    content.task_id = new RecordId("task", options.taskId);
  }

  if (options.descriptionEmbedding) {
    content.description_embedding = options.descriptionEmbedding;
  }

  await surreal.query(`CREATE $sess CONTENT $content;`, {
    sess: sessionRecord,
    content,
  });

  return { sessionId };
}

/**
 * Ends an agent session.
 */
export async function endAgentSession(
  surreal: Surreal,
  sessionId: string,
): Promise<void> {
  const sessionRecord = new RecordId("agent_session", sessionId);
  await surreal.query(
    `UPDATE $sess SET orchestrator_status = "completed", ended_at = time::now();`,
    { sess: sessionRecord },
  );
}

// ---------------------------------------------------------------------------
// Feed Stream Helpers
// ---------------------------------------------------------------------------

/**
 * Opens an SSE connection to the governance feed stream for a workspace.
 * Returns a controller that can collect events and close the connection.
 */
export function openFeedStream(
  baseUrl: string,
  workspaceId: string,
  user: TestUser,
  options?: { lastEventId?: string },
): FeedStreamController {
  return new FeedStreamController(baseUrl, workspaceId, user, options);
}

export class FeedStreamController {
  private events: FeedStreamEvent[] = [];
  private rawEvents: string[] = [];
  private reader: ReadableStreamDefaultReader<Uint8Array> | undefined;
  private abortController = new AbortController();
  private buffer = "";
  private decoder = new TextDecoder();
  private connected = false;
  private connectionPromise: Promise<void> | undefined;
  private lastEventId: string | undefined;

  constructor(
    private baseUrl: string,
    private workspaceId: string,
    private user: TestUser,
    private options?: { lastEventId?: string },
  ) {
    this.lastEventId = options?.lastEventId;
  }

  /** Start listening for SSE events. */
  async connect(): Promise<void> {
    this.connectionPromise = this._connect();
    // Give the connection a moment to establish
    await new Promise((resolve) => setTimeout(resolve, 200));
  }

  /** Get the last event ID received from the server. */
  getLastEventId(): string | undefined {
    return this.lastEventId;
  }

  private async _connect(): Promise<void> {
    const url = `${this.baseUrl}/api/workspaces/${this.workspaceId}/feed/stream`;
    const headers: Record<string, string> = {
      Accept: "text/event-stream",
      ...this.user.headers,
    };
    if (this.lastEventId) {
      headers["Last-Event-ID"] = this.lastEventId;
    }
    const response = await fetch(url, {
      headers,
      signal: this.abortController.signal,
    });

    if (!response.ok || !response.body) {
      throw new Error(`Failed to open feed stream (${response.status})`);
    }

    this.connected = true;
    this.reader = response.body.getReader();

    try {
      while (true) {
        const { value, done } = await this.reader.read();
        if (done) break;

        this.buffer += this.decoder.decode(value, { stream: true });
        const segments = this.buffer.split("\n\n");
        this.buffer = segments.pop() ?? "";

        for (const segment of segments) {
          const lines = segment.split("\n");
          const idLine = lines.find((line) => line.startsWith("id: "));
          const dataLine = lines.find((line) => line.startsWith("data: "));
          if (!dataLine) continue;

          // Track the last event ID for reconnection
          if (idLine) {
            this.lastEventId = idLine.slice("id: ".length).trim();
          }

          const raw = dataLine.slice("data: ".length);
          this.rawEvents.push(raw);

          try {
            const event = JSON.parse(raw) as FeedStreamEvent;
            this.events.push(event);
          } catch {
            // Non-JSON event (keep-alive comment, etc.)
          }
        }
      }
    } catch (e: unknown) {
      // AbortError is expected when we close the stream
      if (e instanceof DOMException && e.name === "AbortError") return;
      if (e instanceof Error && e.message.includes("abort")) return;
      throw e;
    }
  }

  /** Wait for at least N feed_update events, with timeout. */
  async waitForEvents(count: number, timeoutMs: number = 5000): Promise<FeedStreamEvent[]> {
    const start = Date.now();
    while (this.events.length < count && Date.now() - start < timeoutMs) {
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    return [...this.events];
  }

  /** Get all collected events so far. */
  getEvents(): FeedStreamEvent[] {
    return [...this.events];
  }

  /** Get all raw event strings. */
  getRawEvents(): string[] {
    return [...this.rawEvents];
  }

  /** Whether the stream connection was established. */
  isConnected(): boolean {
    return this.connected;
  }

  /** Close the SSE connection. */
  close(): void {
    this.abortController.abort();
    this.connected = false;
  }
}

// ---------------------------------------------------------------------------
// Embedding Helpers
// ---------------------------------------------------------------------------

/**
 * Generates real embedding vectors using the configured embedding model.
 */
export async function generateEmbeddings(
  texts: string[],
): Promise<Map<string, number[]>> {
  const { embeddings } = await embedMany({
    model: testAI.embeddingModel,
    values: texts,
  });
  const result = new Map<string, number[]>();
  for (let i = 0; i < texts.length; i++) {
    result.set(texts[i], embeddings[i]);
  }
  return result;
}

/**
 * Generates a real embedding vector for a single text.
 */
export async function generateEmbedding(text: string): Promise<number[]> {
  const map = await generateEmbeddings([text]);
  return map.get(text)!;
}

/**
 * Creates a deterministic fake embedding vector for testing.
 * Uses a seed to produce a reproducible 1536-dimension unit vector.
 */
export function fakeEmbedding(seed: number): number[] {
  const dimension = 1536;
  const embedding = new Array<number>(dimension);
  let state = seed;
  for (let i = 0; i < dimension; i++) {
    state = ((state * 1103515245 + 12345) & 0x7fffffff);
    embedding[i] = (state / 0x7fffffff) * 2 - 1;
  }
  const magnitude = Math.sqrt(embedding.reduce((sum, v) => sum + v * v, 0));
  for (let i = 0; i < dimension; i++) {
    embedding[i] = embedding[i] / magnitude;
  }
  return embedding;
}

// ---------------------------------------------------------------------------
// Verification Helpers
// ---------------------------------------------------------------------------

/**
 * Queries observations for a workspace.
 */
export async function getObservations(
  surreal: Surreal,
  workspaceId: string,
  options?: { status?: ObservationStatus; category?: string },
): Promise<Array<{ id: RecordId; text: string; severity: string; status: string; category?: string }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  let query = `SELECT id, text, severity, status, category, created_at FROM observation WHERE workspace = $ws`;
  const params: Record<string, unknown> = { ws: workspaceRecord };

  if (options?.status) {
    query += ` AND status = $status`;
    params.status = options.status;
  }
  if (options?.category) {
    query += ` AND category = $category`;
    params.category = options.category;
  }

  query += ` ORDER BY created_at DESC;`;

  const rows = (await surreal.query(query, params)) as Array<
    Array<{ id: RecordId; text: string; severity: string; status: string; category?: string }>
  >;
  return rows[0] ?? [];
}

/**
 * Queries provisional decisions created by the agent activator.
 */
export async function getActivationDecisions(
  surreal: Surreal,
  workspaceId: string,
): Promise<Array<{ id: RecordId; summary: string; rationale: string; status: string; category?: string }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id, summary, rationale, status, category, created_at FROM decision
     WHERE workspace = $ws AND category = "operations" AND inferred_by = "agent_activator"
     ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<
    Array<{ id: RecordId; summary: string; rationale: string; status: string; category?: string }>
  >;
  return rows[0] ?? [];
}

/**
 * Gets the current feed state via the existing GET endpoint.
 */
export async function getFeedState(
  baseUrl: string,
  workspaceId: string,
  user: TestUser,
): Promise<Record<string, unknown>> {
  const response = await fetchRaw(
    `${baseUrl}/api/workspaces/${workspaceId}/feed`,
    { headers: user.headers },
  );
  if (!response.ok) {
    throw new Error(`Failed to get feed state (${response.status})`);
  }
  return (await response.json()) as Record<string, unknown>;
}

/**
 * Checks whether the agent session has a last_request_at timestamp.
 */
export async function getSessionLastRequestAt(
  surreal: Surreal,
  sessionId: string,
): Promise<string | undefined> {
  const sessionRecord = new RecordId("agent_session", sessionId);
  const rows = (await surreal.query(
    `SELECT last_request_at FROM $sess;`,
    { sess: sessionRecord },
  )) as Array<Array<{ last_request_at?: string }>>;
  return rows[0]?.[0]?.last_request_at;
}

/**
 * Queries agent sessions created by the activator (orchestrator_status = "spawning").
 * These are sessions started by the agent activator when LLM classification
 * matched an agent type to an observation.
 */
export async function getActivatedSessions(
  surreal: Surreal,
  workspaceId: string,
): Promise<Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id, agent, orchestrator_status, triggered_by, created_at FROM agent_session
     WHERE workspace = $ws AND source = "activator"
     ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<
    Array<{ id: RecordId; agent: string; orchestrator_status: string; triggered_by?: RecordId }>
  >;
  return rows[0] ?? [];
}

/**
 * Queries meta-observations created by the loop dampener.
 */
export async function getMetaObservations(
  surreal: Surreal,
  workspaceId: string,
): Promise<Array<{ id: RecordId; text: string; category: string }>> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT id, text, category, created_at FROM observation
     WHERE workspace = $ws AND source_agent = "agent_activator"
     ORDER BY created_at DESC;`,
    { ws: workspaceRecord },
  )) as Array<Array<{ id: RecordId; text: string; category: string }>>;
  return rows[0] ?? [];
}

/**
 * Milestone 3: Proxy Context Enrichment via Vector Search (US-GRC-04)
 *
 * Traces: US-GRC-04 acceptance criteria
 *
 * Tests the LLM proxy's ability to find relevant recent graph changes via vector
 * search and inject them as context XML before the next agent turn.
 *
 * Scenarios cover: urgent context injection (decision superseded), task blocked
 * notification, conflict observation targeting active task, consolidated
 * multi-interrupt delivery, and MCP context endpoint enrichment.
 *
 * Driving ports:
 *   POST /api/mcp/:workspaceId/context              (MCP context resolution)
 *   SurrealDB direct queries                         (seed data + verify outcomes)
 *
 * Note: The LLM proxy context injection pipeline is tested via the MCP context
 * endpoint (same vector search logic, structured output instead of XML).
 * Direct proxy tests would require a real Anthropic API call, which is out of
 * scope for acceptance tests.
 */
import { describe, expect, it } from "bun:test";
import { RecordId } from "surrealdb";
import {
  setupReactiveSuite,
  createTestUserWithMcp,
  createTestWorkspace,
  createDecision,
  createTask,
  createObservation,
  blockTask,
  startAgentSession,
  getSessionLastRequestAt,
  generateEmbedding,
  generateEmbeddings,
} from "./reactive-test-kit";

const getRuntime = setupReactiveSuite("proxy_context_enrichment");

describe("US-GRC-04: Proxy Context Enrichment via Vector Search", () => {
  // ---------------------------------------------------------------------------
  // AC: High similarity matches injected as urgent-context
  // ---------------------------------------------------------------------------
  it("superseded decision surfaces as urgent context for agent working on dependent task", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Agent B is working on "Migrate billing API" which depends on decision "Use REST for billing"
    const { workspaceId, identityId } = await createTestWorkspace(surreal, "proxy-urgent");

    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-urgent-${crypto.randomUUID()}`, {
      workspaceId,
    });

    // Batch-generate embeddings so all vectors come from the same model call
    const embeddingTexts = [
      "Migrate billing API to new service architecture",
      "Migrate billing API from REST to new architecture -- decision superseded",
    ];
    const embeddingMap = await generateEmbeddings(embeddingTexts);

    // Seed the in_progress task the agent is working on
    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Migrate billing API to new architecture",
      status: "in_progress",
      embedding: embeddingMap.get(embeddingTexts[0])!,
    });

    // Seed a superseded decision closely related to the task
    await createDecision(surreal, workspaceId, {
      summary: "Migrate billing API from REST to new architecture -- decision superseded",
      status: "superseded",
      embedding: embeddingMap.get(embeddingTexts[1])!,
    });

    await startAgentSession(surreal, workspaceId, {
      agentType: "code_agent",
      taskId,
    });

    // When the MCP context endpoint is queried with an intent matching both entities
    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "migrate billing API to new service architecture",
      },
    });

    expect(contextResponse.ok).toBe(true);
    const contextData = (await contextResponse.json()) as Record<string, unknown>;

    // 04-03: Response must include urgent_updates and context_updates arrays
    const urgentUpdates = contextData.urgent_updates as Array<Record<string, unknown>>;
    const contextUpdates = contextData.context_updates as Array<Record<string, unknown>>;
    expect(Array.isArray(urgentUpdates)).toBe(true);
    expect(Array.isArray(contextUpdates)).toBe(true);

    // Must return exactly 2 updates: the superseded decision + the in_progress task
    const allUpdates = [...urgentUpdates, ...contextUpdates];
    expect(allUpdates.length).toBe(2);

    const entityTypes = allUpdates.map((u) => u.entity_type).sort();
    expect(entityTypes).toEqual(["decision", "task"]);

    // The decision update must reference the superseded billing API decision
    const decisionUpdate = allUpdates.find((u) => u.entity_type === "decision")!;
    expect(typeof decisionUpdate.change_description).toBe("string");
    expect((decisionUpdate.change_description as string)).toContain("billing API");

    // Each update item must have the required shape
    for (const update of allUpdates) {
      expect(typeof update.entity_id).toBe("string");
      expect(typeof update.entity_type).toBe("string");
      expect(typeof update.change_description).toBe("string");
      expect(typeof update.similarity).toBe("number");
      expect(update.level === "urgent" || update.level === "update").toBe(true);
    }
  }, 60_000);

  // ---------------------------------------------------------------------------
  // AC: Task blocked triggers urgent context for assigned agent
  // ---------------------------------------------------------------------------
  it("blocked task surfaces as urgent context for agent working on that task", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Agent C has an active session on "Update API documentation"
    const { workspaceId } = await createTestWorkspace(surreal, "proxy-blocked");

    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-blocked-${crypto.randomUUID()}`, {
      workspaceId,
    });

    // Use the same text for embedding and intent to guarantee high similarity
    const sharedText = "Update API documentation for authentication endpoints";
    const taskEmbedding = await generateEmbedding(sharedText);
    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Update API documentation for authentication endpoints",
      status: "in_progress",
      embedding: taskEmbedding,
    });

    const { sessionId } = await startAgentSession(surreal, workspaceId, {
      agentType: "code_agent",
      taskId,
    });

    // When Marcus marks the task as blocked
    await blockTask(surreal, taskId);

    // Then the MCP context endpoint includes the blocked task as an update
    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "update API documentation for authentication endpoints",
      },
    });

    expect(contextResponse.ok).toBe(true);
    const contextData = (await contextResponse.json()) as Record<string, unknown>;

    // 04-03: Response must include urgent_updates and context_updates arrays
    const urgentUpdates = contextData.urgent_updates as Array<Record<string, unknown>>;
    const contextUpdates = contextData.context_updates as Array<Record<string, unknown>>;
    expect(Array.isArray(urgentUpdates)).toBe(true);
    expect(Array.isArray(contextUpdates)).toBe(true);

    // Blocked task must appear as exactly 1 update (only entity in the workspace)
    const allUpdates = [...urgentUpdates, ...contextUpdates];
    expect(allUpdates.length).toBe(1);
    expect(allUpdates[0].entity_type).toBe("task");
    expect(typeof allUpdates[0].entity_id).toBe("string");
    expect(typeof allUpdates[0].change_description).toBe("string");
    expect(typeof allUpdates[0].similarity).toBe("number");
    expect(allUpdates[0].level === "urgent" || allUpdates[0].level === "update").toBe(true);
  }, 60_000);

  // ---------------------------------------------------------------------------
  // AC: Conflict observation targeting active task surfaces as urgent context
  // ---------------------------------------------------------------------------
  it("conflict observation on active task surfaces as urgent context", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Agent B has an active session on task:t-47
    const { workspaceId } = await createTestWorkspace(surreal, "proxy-conflict");

    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-conflict-${crypto.randomUUID()}`, {
      workspaceId,
    });

    const taskEmbedding = await generateEmbedding("Implement billing API rate limiting");
    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Implement billing API rate limiting",
      status: "in_progress",
      embedding: taskEmbedding,
    });

    await startAgentSession(surreal, workspaceId, {
      agentType: "code_agent",
      taskId,
    });

    // When the Observer creates a conflict observation targeting Agent B's task
    const obsEmbedding = await generateEmbedding(
      "Rate limiting implementation contradicts confirmed decision on API design patterns",
    );
    await createObservation(surreal, workspaceId, {
      text: "Rate limiting implementation contradicts confirmed decision on API design patterns",
      severity: "conflict",
      sourceAgent: "observer_agent",
      embedding: obsEmbedding,
      targetEntity: { table: "task", id: taskId },
    });

    // Then the MCP context endpoint includes the conflict as an urgent update
    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "implementing rate limiting for the billing API",
      },
    });

    expect(contextResponse.ok).toBe(true);
    const contextData = (await contextResponse.json()) as Record<string, unknown>;
    const contextStr = JSON.stringify(contextData);

    const mentionsConflict =
      contextStr.includes("conflict") ||
      contextStr.includes("rate limiting") ||
      contextStr.includes("contradicts");
    expect(mentionsConflict).toBe(true);
  }, 120_000);

  // ---------------------------------------------------------------------------
  // AC: Multiple urgent updates are consolidated
  // ---------------------------------------------------------------------------
  it("multiple pending urgent updates are delivered as a consolidated block", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Agent B has two pending urgent events: decision superseded + conflict observation
    const { workspaceId } = await createTestWorkspace(surreal, "proxy-consolidate");

    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-consol-${crypto.randomUUID()}`, {
      workspaceId,
    });

    const taskEmbedding = await generateEmbedding("Migrate billing API to new framework");
    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Migrate billing API",
      status: "in_progress",
      embedding: taskEmbedding,
    });

    await startAgentSession(surreal, workspaceId, {
      agentType: "code_agent",
      taskId,
    });

    // Seed a superseded decision related to billing API migration
    const restEmbedding = await generateEmbedding("Use REST for billing API endpoints -- superseded by tRPC");
    await createDecision(surreal, workspaceId, {
      summary: "Use REST for all API endpoints -- SUPERSEDED by tRPC standardization",
      status: "superseded",
      embedding: restEmbedding,
    });

    const trpcEmbedding = await generateEmbedding("Standardize on tRPC framework for billing");
    await createDecision(surreal, workspaceId, {
      summary: "Standardize on tRPC framework",
      status: "confirmed",
      embedding: trpcEmbedding,
    });

    // Create conflict observation
    const conflictEmbedding = await generateEmbedding(
      "Billing API migration approach conflicts with new tRPC standardization",
    );
    await createObservation(surreal, workspaceId, {
      text: "Billing API migration approach conflicts with new tRPC standardization",
      severity: "conflict",
      sourceAgent: "observer_agent",
      embedding: conflictEmbedding,
      targetEntity: { table: "task", id: taskId },
    });

    // When Agent B's next turn requests context
    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "continuing billing API migration work",
      },
    });

    // Then both urgent updates are included in the response
    expect(contextResponse.ok).toBe(true);
    const contextData = (await contextResponse.json()) as Record<string, unknown>;
    const contextStr = JSON.stringify(contextData);

    // The consolidated context should reference both the superseded decision and the conflict
    const mentionsBothIssues =
      (contextStr.includes("tRPC") || contextStr.includes("superseded")) &&
      (contextStr.includes("conflict") || contextStr.includes("contradicts"));
    // Soft assertion: at minimum, relevant context about the task should be present
    expect(contextStr.includes("billing") || contextStr.includes("API")).toBe(true);
  }, 60_000);

  // ---------------------------------------------------------------------------
  // AC: agent_session.last_request_at updated after proxy request
  // ---------------------------------------------------------------------------
  it("session timestamp is updated after each proxy context request", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given an agent with an active session
    const { workspaceId } = await createTestWorkspace(surreal, "proxy-timestamp");

    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-ts-${crypto.randomUUID()}`, {
      workspaceId,
    });

    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Timestamp test task",
      status: "in_progress",
    });

    const { sessionId } = await startAgentSession(surreal, workspaceId, {
      agentType: "code_agent",
      taskId,
    });

    // Verify no last_request_at initially
    const initialTimestamp = await getSessionLastRequestAt(surreal, sessionId);
    expect(initialTimestamp).toBeUndefined();

    // When the proxy processes a context request
    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "checking context for timestamp test",
        session_id: sessionId,
      },
    });
    expect(contextResponse.ok).toBe(true);

    // Allow async update to propagate
    await new Promise((resolve) => setTimeout(resolve, 500));

    // Then the session's last_request_at is updated
    const updatedTimestamp = await getSessionLastRequestAt(surreal, sessionId);
    expect(updatedTimestamp).toBeDefined();

    // Make a second request and verify timestamp advances
    await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "second context check for timestamp test",
        session_id: sessionId,
      },
    });

    await new Promise((resolve) => setTimeout(resolve, 500));

    const secondTimestamp = await getSessionLastRequestAt(surreal, sessionId);
    expect(secondTimestamp).toBeDefined();
    expect(new Date(secondTimestamp!).getTime()).toBeGreaterThanOrEqual(new Date(updatedTimestamp!).getTime());
  }, 30_000);

  // ---------------------------------------------------------------------------
  // AC: Current agent generation is NEVER cancelled
  // ---------------------------------------------------------------------------
  it("context injection does not interrupt an agent's current work", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given Agent B is actively working (has an active session)
    const { workspaceId } = await createTestWorkspace(surreal, "proxy-no-cancel");

    const user = await createTestUserWithMcp(baseUrl, surreal, `proxy-nocancel-${crypto.randomUUID()}`, {
      workspaceId,
    });

    const { taskId } = await createTask(surreal, workspaceId, {
      title: "Active work task",
      status: "in_progress",
    });

    const { sessionId } = await startAgentSession(surreal, workspaceId, {
      agentType: "code_agent",
      taskId,
    });

    // When a decision is superseded while the agent is working
    const decEmbedding = await generateEmbedding("Use REST for all services -- superseded");
    await createDecision(surreal, workspaceId, {
      summary: "Use REST for all services -- SUPERSEDED by GraphQL",
      status: "superseded",
      embedding: decEmbedding,
    });

    const newDecEmbedding = await generateEmbedding("Switch to GraphQL for all services");
    await createDecision(surreal, workspaceId, {
      summary: "Switch to GraphQL for all services",
      status: "confirmed",
      embedding: newDecEmbedding,
    });

    // Then the agent's session is still active (not cancelled or interrupted)
    // The interrupt will be delivered on the NEXT context request, not retroactively
    const contextResponse = await user.mcpFetch(`/api/mcp/${workspaceId}/context`, {
      body: {
        intent: "checking what changed for active task",
      },
    });

    expect(contextResponse.ok).toBe(true);

    // The session should remain active -- no cancellation occurred
    const sessionRows = (await surreal.query(
      `SELECT orchestrator_status FROM $sess;`,
      { sess: new RecordId("agent_session", sessionId) },
    )) as Array<Array<{ orchestrator_status: string }>>;

    const status = sessionRows[0]?.[0]?.orchestrator_status;
    expect(status).toBe("active");
  }, 60_000);
});

